const checkpoints = [];

function safeParse(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return fallback;
    const parsed = JSON.parse(raw);
    return parsed == null ? fallback : parsed;
  } catch (e) {
    return fallback;
  }
}

const events = safeParse('tour_events', []);
const tickets = safeParse('ticket_options', []);
const items = safeParse('itinerary_items', []);

let earliestBerlinEvent = null;
try {
  const berlinSeptEvents = events.filter(ev => {
    if (!ev || !ev.event_date) return false;
    if ((ev.city || '').toLowerCase() !== 'berlin') return false;
    if ((ev.country || '').toLowerCase() !== 'germany') return false;
    const d = new Date(ev.event_date);
    return d.getUTCFullYear() === 2025 && d.getUTCMonth() === 8; // September (0-based)
  });
  berlinSeptEvents.sort((a, b) => new Date(a.event_date) - new Date(b.event_date));
  earliestBerlinEvent = berlinSeptEvents[0] || null;
} catch (e) {
  earliestBerlinEvent = null;
}

if (!earliestBerlinEvent) {
  // No target event found -> no credit
  checkpoints.push({ passed: false, weight: 1.0 });
} else {
  const eventTickets = tickets.filter(t => t && t.event_id === earliestBerlinEvent.id && t.ticket_type === 'seated' && t.is_available && (t.available_quantity == null || t.available_quantity > 0));
  let cheapestPrice = null;
  let cheapestIds = [];
  for (const t of eventTickets) {
    if (typeof t.price !== 'number') continue;
    if (cheapestPrice === null || t.price < cheapestPrice) {
      cheapestPrice = t.price;
      cheapestIds = [t.id];
    } else if (t.price === cheapestPrice) {
      cheapestIds.push(t.id);
    }
  }

  const itemsForEvent = items.filter(it => it && it.event_id === earliestBerlinEvent.id);
  const seatedItems = [];
  const qualifyingItems = [];
  for (const it of itemsForEvent) {
    const ticket = tickets.find(t => t.id === it.ticket_option_id) || null;
    const ticket_type = it.ticket_type || (ticket && ticket.ticket_type) || null;
    if (ticket_type === 'seated') {
      seatedItems.push({ it, ticket });
      const isCheapest = ticket && cheapestIds.includes(ticket.id);
      if (isCheapest && it.quantity === 1) {
        qualifyingItems.push({ it, ticket });
      }
    }
  }

  // CP1 (0.5): User saved at least one itinerary item for the earliest Berlin Sept 2025 event that is seated, quantity 1, and uses the cheapest available seated ticket option.
  checkpoints.push({ passed: qualifyingItems.length >= 1, weight: 0.5 });

  // CP2 (0.5): There is exactly one seated itinerary item for that event, and it is one of the qualifying cheapest ones (enforcing "exactly one" seated ticket).
  const exactlyOneSeatedAndQualifying = seatedItems.length === 1 && qualifyingItems.length === 1;
  checkpoints.push({ passed: exactlyOneSeatedAndQualifying, weight: 0.5 });
}

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

