const playlists = safeParse('playlists', []);
const playlistTracks = safeParse('playlist_tracks', []);
const tracks = safeParse('tracks', []);

const pl = playlists.find(p => p && p.name === 'Acoustic 2018-22') || null;
let trackIdsInPlaylist = [];
if (pl) {
  const pts = playlistTracks.filter(pt => pt && pt.playlist_id === pl.id).sort((a, b) => a.position - b.position);
  trackIdsInPlaylist = pts.map(pt => pt.track_id);
}

// Compute the 4 most recent qualifying acoustic tracks (2018-2022)
let top4Ids = [];
try {
  const qualifyingTracks = tracks.filter(t => {
    if (!t) return false;
    if (t.primary_genre !== 'acoustic') return false;
    if (typeof t.release_year !== 'number') return false;
    return t.release_year >= 2018 && t.release_year <= 2022;
  });
  qualifyingTracks.sort((a, b) => {
    const da = a.release_date ? new Date(a.release_date).getTime() : 0;
    const db = b.release_date ? new Date(b.release_date).getTime() : 0;
    return db - da; // newest first
  });
  top4Ids = qualifyingTracks.slice(0, 4).map(t => t.id);
} catch (e) {
  top4Ids = [];
}

// CP1 (0.7): Playlist exists, has at least 4 tracks, and its first 4 tracks exactly match the 4 most recent qualifying acoustic tracks in order.
const cp1Passed = !!pl && top4Ids.length === 4 && trackIdsInPlaylist.length >= 4 && top4Ids.every((id, idx) => trackIdsInPlaylist[idx] === id);
checkpoints.push({ passed: cp1Passed, weight: 0.7 });

// CP2 (0.3): Playlist contains exactly 4 tracks, and all of them are among the computed top 4 qualifying tracks (no extra or wrong tracks).
const allTracksAreTop4 = trackIdsInPlaylist.length === 4 && trackIdsInPlaylist.every(id => top4Ids.includes(id));
checkpoints.push({ passed: !!pl && allTracksAreTop4, weight: 0.3 });

return checkPointsReduce(checkpoints);

function checkPointsReduce(cps) {
  return cps.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
}

