const products = safeParse('products', []);
const cartItems = safeParse('cart_items', []);

function getProduct(id) {
  return products.find(p => p && p.id === id) || null;
}

// Find all qualifying T-shirts (global) according to task filters
const eligibleShirts = products.filter(p => {
  if (!p || !p.is_active) return false;
  if (p.product_type !== 't_shirt') return false;
  if (!Array.isArray(p.sizes_available) || !p.sizes_available.includes('m')) return false;
  const rating = typeof p.average_rating === 'number' ? p.average_rating : 0;
  if (rating < 4) return false;
  if (p.currency !== 'usd') return false;
  if (typeof p.price !== 'number' || p.price > 40) return false;
  return true;
});

let cheapestShirtPrice = null;
let cheapestShirts = [];
for (const p of eligibleShirts) {
  if (cheapestShirtPrice === null || p.price < cheapestShirtPrice) {
    cheapestShirtPrice = p.price;
    cheapestShirts = [p];
  } else if (p.price === cheapestShirtPrice) {
    cheapestShirts.push(p);
  }
}

// Eligible hoodies depend on cheapest shirt price (budget constraint)
const eligibleHoodies = products.filter(p => {
  if (!p || !p.is_active) return false;
  if (p.product_type !== 'hoodie') return false;
  if (!Array.isArray(p.sizes_available) || !p.sizes_available.includes('m')) return false;
  const rating = typeof p.average_rating === 'number' ? p.average_rating : 0;
  if (rating < 4) return false;
  if (p.currency !== 'usd') return false;
  if (cheapestShirtPrice == null) return false;
  if (typeof p.price !== 'number') return false;
  return p.price + cheapestShirtPrice <= 80;
});

let highestHoodieRating = null;
let highestHoodies = [];
for (const p of eligibleHoodies) {
  const rating = typeof p.average_rating === 'number' ? p.average_rating : 0;
  if (highestHoodieRating === null || rating > highestHoodieRating) {
    highestHoodieRating = rating;
    highestHoodies = [p];
  } else if (rating === highestHoodieRating) {
    highestHoodies.push(p);
  }
}

// Identify cart items that match the cheapest qualifying T-shirt(s)
const tshirtItems = cartItems.filter(ci => {
  const p = getProduct(ci.product_id);
  if (!p) return false;
  if (p.product_type !== 't_shirt') return false;
  if (ci.size !== 'm') return false;
  if (!cheapestShirts.some(s => s.id === p.id)) return false;
  return ci.quantity >= 1;
});

// Identify cart items that match the highest-rated qualifying hoodie(s) within budget
const hoodieItems = cartItems.filter(ci => {
  const p = getProduct(ci.product_id);
  if (!p) return false;
  if (p.product_type !== 'hoodie') return false;
  if (ci.size !== 'm') return false;
  if (!highestHoodies.some(h => h.id === p.id)) return false;
  if (cheapestShirtPrice == null || typeof p.price !== 'number') return false;
  if (p.price + cheapestShirtPrice > 80) return false;
  return ci.quantity >= 1;
});

// CP1 (0.7): Cart contains at least one medium T-shirt that is among the globally cheapest qualifying shirts and at least one medium hoodie that is among the globally highest-rated qualifying hoodies within the budget.
const cp1Passed = tshirtItems.length >= 1 && hoodieItems.length >= 1 && cheapestShirts.length > 0 && highestHoodies.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.7 });

// CP2 (0.3): Exactly one qualifying medium T-shirt item and exactly one qualifying medium hoodie item in the cart (enforcing one of each).
const cp2Passed = tshirtItems.length === 1 && hoodieItems.length === 1;
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

