const subs = safeParse('newsletter_subscriptions', []);
const interests = safeParse('newsletter_interests', []);
const sub = subs[0] || null;

let uniqueCount = 0;
let allCodesValid = false;
if (sub && Array.isArray(sub.interest_codes)) {
  const codes = sub.interest_codes.filter(c => typeof c === 'string');
  const unique = Array.from(new Set(codes));
  uniqueCount = unique.length;
  const validSet = new Set(interests.map(i => i.code));
  allCodesValid = uniqueCount > 0 && unique.every(c => validSet.has(c));
}

// CP1 (0.6): Subscription exists, is active, frequency is weekly, terms are accepted, and there are at least 3 distinct interest codes.
const cp1Passed = !!sub && sub.status === 'active' && sub.frequency === 'weekly' && !!sub.accepted_terms && uniqueCount >= 3;
checkpoints.push({ passed: cp1Passed, weight: 0.6 });

// CP2 (0.4): The same subscription has at least 3 distinct interests and all selected interest codes are valid predefined newsletter topics.
const cp2Passed = !!sub && uniqueCount >= 3 && allCodesValid;
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

