const albums = safeParse('albums', []);
const filterParams = safeParse('task5_albumFilterParams', null);
let comparedIdsRaw = safeParse('task5_comparedAlbumIds', []);
const comparedIds = Array.isArray(comparedIdsRaw) ? comparedIdsRaw : [];

// Determine the two most recent studio albums between 2015 and 2023
const eligibleAlbums = albums.filter(a => {
  if (!a) return false;
  if (a.album_type !== 'studio_album') return false;
  if (typeof a.release_year !== 'number') return false;
  return a.release_year >= 2015 && a.release_year <= 2023;
});
eligibleAlbums.sort((a, b) => {
  const da = a.release_date ? new Date(a.release_date).getTime() : 0;
  const db = b.release_date ? new Date(b.release_date).getTime() : 0;
  return db - da; // newest first
});
const topTwo = eligibleAlbums.slice(0, 2);

let winner = null;
let loser = null;
if (topTwo.length === 2) {
  const underLimit = topTwo.filter(a => typeof a.total_duration_seconds === 'number' && a.total_duration_seconds <= 3600);
  if (underLimit.length > 0) {
    winner = underLimit.reduce((best, a) => {
      if (!best) return a;
      if (a.total_tracks > best.total_tracks) return a;
      if (a.total_tracks === best.total_tracks) {
        const da = a.release_date ? new Date(a.release_date).getTime() : 0;
        const db = best.release_date ? new Date(best.release_date).getTime() : 0;
        return da > db ? a : best;
      }
      return best;
    }, null);
    loser = topTwo.find(a => a.id !== winner.id) || null;
  }
}

// CP1 (0.3): User used correct album filter parameters: studio albums, years 2015–2023, sorted by release_date_desc.
const cp1Passed = !!filterParams && filterParams.album_type === 'studio_album' && filterParams.year_from === 2015 && filterParams.year_to === 2023 && filterParams.sort_order === 'release_date_desc';
checkpoints.push({ passed: cp1Passed, weight: 0.3 });

// CP2 (0.3): User compared the two most recent eligible studio albums (both of their IDs appear in task5_comparedAlbumIds).
const cp2Passed = topTwo.length === 2 && topTwo.every(a => comparedIds.includes(a.id));
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.4): Among those two, the correct winner (more tracks under 60 minutes, then newer if tie) is favorited, and the other is not.
let cp3Passed = false;
if (winner && loser) {
  const winnerState = albums.find(a => a.id === winner.id) || null;
  const loserState = albums.find(a => a.id === loser.id) || null;
  cp3Passed = !!winnerState && winnerState.is_favorite === true && !!loserState && loserState.is_favorite !== true;
}
checkpoints.push({ passed: cp3Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

