const videos = safeParse('videos', []);
const watchLaterItems = safeParse('watch_later_items', []);

const cutoff = new Date('2023-01-01T00:00:00Z').getTime();

const qualifyingVideos = videos.filter(v => {
  if (!v) return false;
  if (v.content_type !== 'live_performance') return false;
  if (!v.recorded_date) return false;
  const rd = new Date(v.recorded_date).getTime();
  if (isNaN(rd) || rd <= cutoff) return false;
  if (typeof v.duration_seconds !== 'number' || v.duration_seconds < 300) return false; // at least 5 minutes
  if (typeof v.view_count !== 'number' || v.view_count < 10000) return false;
  return true;
});

let topViewCount = null;
let topVideos = [];
for (const v of qualifyingVideos) {
  if (topViewCount === null || v.view_count > topViewCount) {
    topViewCount = v.view_count;
    topVideos = [v];
  } else if (v.view_count === topViewCount) {
    topVideos.push(v);
  }
}
const topIds = topVideos.map(v => v.id);

const qualifyingItems = watchLaterItems.filter(it => qualifyingVideos.some(v => v.id === it.video_id));
const uniqueQualifyingVideoIds = Array.from(new Set(qualifyingItems.map(it => it.video_id)));
const savedTopIds = uniqueQualifyingVideoIds.filter(id => topIds.includes(id));

// CP1 (0.6): At least one video saved to Watch Later is a qualifying live performance and is among the highest-view qualifying videos.
const cp1Passed = uniqueQualifyingVideoIds.length >= 1 && savedTopIds.length >= 1 && topIds.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.6 });

// CP2 (0.4): Exactly one unique qualifying video has been added, and it is one of the highest-view qualifying videos (enforcing exactly one and best choice).
const cp2Passed = uniqueQualifyingVideoIds.length === 1 && savedTopIds.length === 1;
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

