const events = safeParse('tour_events', []);
const tickets = safeParse('ticket_options', []);
const items = safeParse('itinerary_items', []);

// Find October 2025 events that have at least one available GA ticket option
const octEvents = events.filter(ev => {
  if (!ev || !ev.event_date) return false;
  const d = new Date(ev.event_date);
  if (d.getUTCFullYear() !== 2025 || d.getUTCMonth() !== 9) return false; // October (0-based)
  const gaOptions = tickets.filter(t => t && t.event_id === ev.id && t.ticket_type === 'general_admission' && t.is_available && (t.available_quantity == null || t.available_quantity > 0));
  return gaOptions.length > 0;
});

octEvents.sort((a, b) => new Date(a.event_date) - new Date(b.event_date));
const earliestEvent = octEvents[0] || null;
let secondEvent = null;
if (earliestEvent) {
  secondEvent = octEvents.slice(1).find(ev => ev.country !== earliestEvent.country) || null;
}

if (!earliestEvent || !secondEvent) {
  checkpoints.push({ passed: false, weight: 1.0 });
} else {
  function isItemGAForEvent(it, targetEventId) {
    if (!it || it.event_id !== targetEventId) return false;
    const ticket = tickets.find(t => t.id === it.ticket_option_id) || null;
    const ticket_type = it.ticket_type || (ticket && ticket.ticket_type) || null;
    return ticket_type === 'general_admission';
  }

  const hasGAEarliest = items.some(it => isItemGAForEvent(it, earliestEvent.id));
  const hasGASecond = items.some(it => isItemGAForEvent(it, secondEvent.id));

  // CP1 (0.4): Itinerary includes a GA ticket item for the earliest October 2025 event.
  checkpoints.push({ passed: hasGAEarliest, weight: 0.4 });

  // CP2 (0.6): Itinerary includes GA ticket items for both the earliest and the next-earliest October 2025 events in different countries.
  const cp2Passed = hasGAEarliest && hasGASecond && earliestEvent.country !== secondEvent.country;
  checkpoints.push({ passed: cp2Passed, weight: 0.6 });
}

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

