const tracks = safeParse('tracks', []);
const albums = safeParse('albums', []);
const selection = safeParse('task8_lyricsSelection', null);

const albumMap = {};
for (const a of albums) {
  if (a && a.id) albumMap[a.id] = a;
}

const qualifyingTracks = tracks.filter(t => {
  if (!t || !t.album_id || !t.title) return false;
  const album = albumMap[t.album_id];
  if (!album || typeof album.release_year !== 'number') return false;
  if (album.release_year !== 2020) return false;
  return t.title.toLowerCase().includes('midnight');
});

const selectionQualifies = (() => {
  if (!selection || !selection.track_id || !selection.language) return false;
  const isQualTrack = qualifyingTracks.some(t => t.id === selection.track_id);
  const lang = String(selection.language).toLowerCase();
  const isSpanish = lang === 'es' || lang === 'spanish';
  return isQualTrack && isSpanish;
})();

// CP1 (0.5): User viewed lyrics in Spanish for a track from a 2020 album whose title includes 'midnight'.
checkpoints.push({ passed: selectionQualifies, weight: 0.5 });

// CP2 (0.5): That same qualifying track has been marked as favorite.
let cp2Passed = false;
if (selectionQualifies) {
  const track = tracks.find(t => t && t.id === selection.track_id) || null;
  cp2Passed = !!track && track.is_favorite === true;
}
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
